CREATE TABLE `wp_platform_requests` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `college_user_id` bigint(20) unsigned NOT NULL,
  `topic` text DEFAULT NULL,
  `cohort_size` int(10) unsigned DEFAULT NULL,
  `preferred_slots` longtext DEFAULT NULL,
  `shortlisted_experts` longtext DEFAULT NULL,
  `status` varchar(20) NOT NULL DEFAULT 'pending',
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT NULL,
  `expert_user_id` bigint(20) NOT NULL,
  `description` text DEFAULT NULL,
  `proposed_start_iso` varchar(30) DEFAULT NULL,
  `duration_minutes` int(11) DEFAULT 60,
  `capacity` int(11) DEFAULT 100,
  `price_offer` decimal(10,2) DEFAULT 0.00,
  `order_id` bigint(20) DEFAULT NULL,
  `appointment_id` bigint(20) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_college` (`college_user_id`),
  KEY `idx_status` (`status`),
  KEY `college_user_id` (`college_user_id`),
  KEY `expert_user_id` (`expert_user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=125 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
